trigger.body:

v_message varchar(255);

BEGIN


IF (UPDATING) THEN
        if :old.entregado='Y' and :old.cantidad<>:new.cantidad then 

                v_message:='No se puede editar la línea - Producto Despachado - Crear una nueva línea y despachar';
                RAISE v_message;

        else 

               return new;

        end if;
end if;

END ATINDPO_VAL_CANTIDAD_LIN_TRG
